let nouvelleMesure = {
    //si les valeurs envoyées ne sont pas trouvables le code écrit un 0 au lieu d'avoir une valeur vide
    temperature: donneesRobot.temperature || 0,
    humidite: donneesRobot.humidite || 0,
    pression: donneesRobot.pression || 0,
    luminosite: donneesRobot.luminosite || 0,
    vitesse_m_s: donneesRobot.vitesse_m_s || 0,
    dirVent: donneesRobot.dirVent || 0,
