    pluie_mm: donneesRobot.pluie_mm || 0,
    lng: donneesRobot.lng || 0,
    alt: donneesRobot.alt || 0,
    lat: donneesRobot.lat || 0,
    speed: donneesRobot.speed || 0,
    //donne la date et l'heure sur le fuseau horaire de paris
    date: new Date().toISOString() };

global.set("mesure_actuelle", nouvelleMesure);//range l'objet nouvelleMesure dans un tiroir de la mémoire globale appelé "mesure_actuelle"

let historique = global.get("historique") || [];//créé une liste vide pour l'historique
historique.unshift(nouvelleMesure);//insère la toute nouvelle mesure tout en haut de la liste
//si l'historique dépasse 100 lignes, le mot pop() jette automatiquement la mesure la plus vieille pour éviter les problèmes de mémoire
if (historique.length > 100) { historique.pop(); }
global.set("historique", historique);//range les nouveautés dans la mémoire 

